import { api, z, postgres } from "@superblocksteam/sdk-api";

const APPS_DB = "c6e32cf4-ca66-42ae-aeb3-58c84ffae574";
const ADMIN_EMAILS = ["jt.bohland@amplitude.com"];

/**
 * V1 questions for days 1-9, normalized to v2 format:
 * - match questions: prompt/answer → term/match
 * - fill questions: acceptedAnswers → correct
 * - tf questions: options normalized to ["True","False"]
 * - resource URLs mapped from v2 data per question
 */

const DAY1_ICP = "https://docs.google.com/presentation/d/1i6jAipawDy9ER5Bls-FFdXdr4hQA41XKw-wYqK5RttE/edit";

const v1Day1 = [
  { id: 1, type: "mc", lo: "LO1", text: "Amplitude focuses its GTM efforts on five core industries. Which of the following is NOT one of them?", options: ["Media & Entertainment","Retail & Ecommerce","Manufacturing & Logistics","Financial Services"], correct: 2, explanation: "Amplitude's five core industries are Retail & Ecommerce, B2B SaaS, Financial Services, Media & Entertainment, and Healthcare. Manufacturing & Logistics is not a focus vertical — when you encounter accounts in that space, it's a signal to deprioritize or nurture rather than pursue aggressively.", resource: { label: "ICP: Personas & Industries Deck", url: DAY1_ICP } },
  { id: 2, type: "mc", lo: "LO1", text: "You're preparing for a first call with a prospect in the Financial Services space. Applying verticalized selling, what's the most important thing to do before the call?", options: ["Build a custom demo using their public product screenshots to show you understand their UX","Review the Financial Services industry hub in Highspot to understand current trends, challenges, one-pagers, and relevant customer stories before jumping on the call","Lead with Amplitude's enterprise security and compliance certifications — FinServ buyers always prioritize data governance first","Skip industry prep and focus on open-ended discovery — you'll learn more from listening than from research"], correct: 1, explanation: "Verticalized selling requires showing up prepared. The Financial Services industry hub in Highspot is the single source of truth — it contains trends, challenges, customer stories, use case matrices, and one-pagers tailored to that vertical. Showing up without doing your homework is obvious to prospects and kills credibility early.", resource: { label: "ICP: Personas & Industries Deck — Industry Content for Prospecting", url: DAY1_ICP } },
  { id: 3, type: "mc", lo: "LO2", text: "A Product Manager tells you: 'We ship features constantly but can't tell which ones are actually getting used or driving retention.' Which Amplitude value driver does this map to, and what's the right discovery follow-up?", options: ["Acquisition — ask how they're sourcing new users and whether they're tracking funnel conversion by channel","Retention — this is a signal they can't find moments of impact or build data-driven roadmaps. Follow up: 'How long does it take to answer a question like: which feature release actually improved 30-day retention?'","Monetization — feature usage directly maps to pricing strategy, so ask whether they've explored usage-based pricing models","Data Governance — the real problem is instrumentation quality, not analysis. Redirect to their data engineering team before continuing"], correct: 1, explanation: "A PM who can't connect feature usage to retention outcomes is describing a core Amplitude use case: finding moments of impact and creating data-driven roadmaps. This maps to the Retention value driver. The Challenger move is to deepen the pain — ask the question that forces them to confront how long it actually takes to get that answer today.", resource: { label: "ICP: Personas & Industries Deck — Product Persona", url: DAY1_ICP } },
  { id: 4, type: "tf", lo: "LO2", text: "True or False: The Data/Analytics persona and the Product persona care about the same outcomes and should receive the same Amplitude value pitch.", options: ["True","False"], correct: 1, explanation: "Personas use Amplitude for different reasons. A Data Analyst's pain is spending too much time cleaning data and servicing reactive requests — they want to do strategic work. A Product Manager's pain is not knowing why users drop off and being unable to validate ideas fast enough. Leading with the wrong value message signals you haven't done your homework and breaks credibility before you've started.", resource: { label: "ICP: Personas & Industries Deck — Personas Use Amplitude for Different Reasons", url: DAY1_ICP } },
  { id: 5, type: "mc", lo: "LO3", text: "You're reviewing your territory. Account A: 180-person B2B SaaS startup, just launched a mobile app, no dedicated analytics tooling beyond Google Analytics. Account B: 3,000-person enterprise media company with an existing Mixpanel contract and a data team of 12. Which do you prioritize and why?", options: ["Account A — smaller companies move faster, there's no incumbent to displace, and the Google Analytics gap is an easy Amplitude conversation","Account B — the Mixpanel contract is an active renewal signal, the data team scale suggests significant analytics investment, and enterprise media is a top-performing Amplitude vertical. The higher complexity is worth it.","Neither — Account A doesn't have the budget and Account B is too entrenched with a competitor to displace","Both equally — ICP fit on paper is the same, so effort should be split evenly until one progresses further"], correct: 1, explanation: "Account B is the higher-priority ICP. Enterprise media is a core Amplitude vertical. An existing Mixpanel contract with renewal visibility is a displacement opportunity, not a blocker — it means budget exists and the problem is validated. A data team of 12 signals serious analytics investment. Account A is worth nurturing but doesn't have the same urgency or deal size potential.", resource: { label: "ICP: Personas & Industries Deck — Top Performing Industries", url: DAY1_ICP } },
  { id: 6, type: "match", lo: "LO2", text: "Match each Amplitude persona to their primary motivation for using the platform.", pairs: [{ term: "Product Manager", match: "Find moments of impact, build data-driven roadmaps, maximize monetization" },{ term: "Data/Analytics", match: "Make it easier to get insights, answer questions instantly, refocus on strategic projects" },{ term: "Marketing", match: "Measure downstream metrics, identify high-value audiences, personalize experiences" },{ term: "Digital Executive", match: "Monitor top KPIs, connect product to revenue, out-innovate competition" }], correct: 0, explanation: "Each persona uses Amplitude differently because their jobs are different. Product Managers need to find what's driving user behavior and validate roadmap decisions. Data Analysts want to stop servicing reactive requests and focus on strategic work. Marketers need to tie campaign activity to downstream product engagement. Executives need a view of the full business — KPIs, revenue, and competitive position. Knowing who you're talking to before the call determines which value driver to lead with.", resource: { label: "ICP: Personas & Industries Deck — Meet Our Personas", url: DAY1_ICP } },
  { id: 7, type: "mc", lo: "LO3", text: "A CMO at a retail company says: 'We care about acquiring customers — we already have Google Analytics for that. We don't need a product analytics tool.' An AE responds: 'Amplitude is more than just product analytics — we have a CDP, experimentation, and session replay too. Let me show you a demo.' What's wrong with this response?", options: ["Nothing — feature breadth is the right counter to a narrow framing, and a demo will let the product sell itself","The AE is leading with product instead of Teaching. The CMO's real problem is likely the gap between campaign activity and downstream revenue — Amplitude can show which campaigns drive high-value users, not just clicks. The AE should reframe the conversation around acquisition outcomes before going anywhere near a feature list.","The AE should have pushed back on the Google Analytics mention first — that's the real objection and it needs to be addressed directly before anything else","The AE is being too aggressive. A better move is to agree with the CMO's framing and ask to connect them with a customer success story instead"], correct: 1, explanation: "This is a Challenger failure. The AE accepted the CMO's frame (we don't need product analytics) and responded with a feature dump — the opposite of Teach. A Marketer's pain is lack of visibility into the full customer journey and data silos that hinder campaign optimization. The right move is to reframe: 'What if you could see not just which campaign drove the most clicks, but which one drove users who actually retained for 90 days?' That's a commercial insight — it challenges their assumption that GA is solving the problem.", resource: { label: "ICP: Personas & Industries Deck — Marketing Persona", url: DAY1_ICP } },
  { id: 8, type: "fill", lo: "LO1", text: "Amplitude's five core industries are Retail & Ecommerce, B2B SaaS, Financial Services, Healthcare, and ________.", correct: ["Media & Entertainment","Media and Entertainment","media & entertainment","media and entertainment"], placeholder: "fifth core industry...", explanation: "Media & Entertainment is Amplitude's fifth core vertical — covering traditional TV like A&E, Disney, and NBCUniversal through to streaming services, gaming, and betting platforms. These five industries anchor virtually all of Amplitude's marketing efforts, content, and field positioning.", resource: { label: "ICP: Personas & Industries Deck — Our Core Industries", url: DAY1_ICP } },
  { id: 9, type: "mc", lo: "LO3", text: "You're prospecting into a 600-person healthcare technology company. Their job board shows they're hiring a 'Director of Product Analytics' and a 'Growth Engineer.' What do these signals tell you about ICP fit and how should you approach the account?", options: ["Weak ICP signal — hiring in these roles suggests they're building internal analytics capabilities, which means they're less likely to buy an external tool","Strong ICP signal — these roles indicate the company is investing in product-led growth and self-serve analytics. They're experiencing the exact pain points Amplitude solves: growth visibility, feature impact, and data-driven product decisions. Prioritize and tailor outreach to each persona's specific motivation.","Moderate ICP signal — wait until you can confirm they don't have an existing analytics contract before investing outreach time","Strong ICP signal — but only if the company is above $500M in revenue. Below that threshold, they won't have budget for an enterprise analytics platform."], correct: 1, explanation: "Job postings are one of the highest-quality ICP signals available. A 'Director of Product Analytics' hire means the company is formalizing their analytics function — they're past the 'we use spreadsheets' stage and actively investing. A 'Growth Engineer' signals product-led growth maturity. Healthcare is a core Amplitude vertical. Together, these signals tell you the account is in the growth phase where Amplitude adds the most value. Tailor outreach separately to the PM and Data personas — they have different motivations.", resource: { label: "ICP: Personas & Industries Deck — Where to Find Industry Content", url: DAY1_ICP } },
  { id: 10, type: "mc", lo: "LO2", text: "You're deep in discovery with a Head of Data at a B2B SaaS company. They say: 'We have Snowflake and our engineers build all of our internal dashboards. We've invested a lot in our data stack.' An AE responds: 'Amplitude can replace a lot of that — it's much easier to use than building custom dashboards.' What's the strategic error here?", options: ["The AE is underselling — they should have mentioned that Amplitude also has a CDP that can replace Snowflake entirely","The AE is positioning Amplitude as a threat to the Data team's work and value, which will make the Head of Data a blocker rather than a champion. The right frame is additive: Amplitude empowers the business teams to self-serve, which frees the Data team to focus on strategic projects instead of servicing reactive requests.","The AE is correct — ease of use is always the right counter to a complex existing stack argument","The AE should have pivoted to a product demo immediately — the Head of Data will only be convinced by seeing the tool, not by a verbal pitch"], correct: 1, explanation: "This is a critical positioning mistake. Telling a Head of Data that Amplitude replaces their custom dashboards is telling them their team's work is unnecessary — instant blocker. The Challenger move is to reframe Amplitude as a force multiplier: 'How many hours a week does your team spend servicing ad hoc requests from product and marketing? What would they do with that time if those teams could self-serve?' This turns the Head of Data from a threat into a potential champion — Amplitude makes them look strategic, not redundant.", resource: { label: "ICP: Personas & Industries Deck — Data/Analytics Persona", url: DAY1_ICP } },
];

const DAY2_TOFU_DECK = "https://docs.google.com/presentation/d/1cFxBuOQyJxSEnN34JrolHsnzc2DhdgUX-bxtBM_xYDM/edit";
const DAY2_TOFU_FAQ = "https://docs.google.com/document/d/14QUw9j82ZGvfDZi7w7hTz44EWibz3DzQieaIbGzsGZY/edit";

const v1Day2 = [
  { id: 1, type: "mc", lo: "LO1", text: "You receive a new MQL notification in Slack. The MQL type is 'Hand Raiser' and you're an Emerging Enterprise AE. How long do you have to make first contact?", options: ["8 business hours","1 business hour","2 business hours","16 business hours"], correct: 2, explanation: "For Emerging Enterprise AEs, the SLA for Hand Raiser MQLs is 2 business hours. Hand Raisers are the highest-priority MQL type — they've directly requested contact from Amplitude. The 1-hour SLA applies to SDRs and Velocity AEs. Knowing your exact SLA by MQL type isn't optional — breaches escalate to your VP after 2 days.", resource: { label: "TOFU Training Deck — Time to First Touch SLAs", url: DAY2_TOFU_DECK } },
  { id: 2, type: "mc", lo: "LO1", text: "A prospect downloads the Northstar Playbook and attends an Amplitude webinar the same week. How many MQLs does this generate in Salesforce?", options: ["Two — one for each marketing interaction","One — the system generates a single MQL per person regardless of how many actions they take, assigned the highest-priority MQL type","Zero — content downloads and webinar attendees don't qualify as MQLs","One — but only if both interactions happen within the same 7-day window"], correct: 1, explanation: "The system generates one MQL per person — not one per action. This was a deliberate design decision: 'when everything is an MQL, nothing is an MQL.' Both a playbook download and a webinar attendance are 'Other MQL' type. If the person had also completed a Contact Us form, the system would assign the Hand Raiser type (higher priority). One person = one MQL = one SLA clock.", resource: { label: "TOFU FAQ — Can a Prospect Be Tagged with Multiple MQL Types?", url: DAY2_TOFU_FAQ } },
  { id: 3, type: "mc", lo: "LO2", text: "You receive a Hand Raiser MQL for a contact at a company you're actively working as an open S1 opportunity. What's the right course of action?", options: ["Reroute the MQL to your SDR — since it's an active opportunity, the SDR should handle inbound interest while you focus on advancing the deal","Ignore the MQL notification — if they're already in an active opportunity they won't re-MQL","Respond to the MQL to satisfy the SLA, then assess whether this contact is part of the same buying group or represents a new opportunity — add them to opportunity contact roles accordingly","Disqualify the MQL with reason 'Duplicate' since they're already in your pipeline"], correct: 2, explanation: "An active opportunity doesn't exempt you from the SLA — the clock is ticking. The right move is to respond first, then assess. If the contact is part of the same buying group, add them to the opportunity contact roles. If they represent a new buying center at the same company, that could be a separate opportunity. 'Duplicate' is not the right disqualification reason — that's for actual duplicate records in Salesforce, not for contacts who are already being actively worked.", resource: { label: "TOFU FAQ — What Do I Do with an MQL in a Prospect Account with an Open Opportunity?", url: DAY2_TOFU_FAQ } },
  { id: 4, type: "tf", lo: "LO1", text: "True or False: If you're going on PTO, your MQLs will automatically be paused until you return.", options: ["True","False"], correct: 1, explanation: "MQLs do not pause for PTO. The SLA clock runs in real time. Before going OOO you must: inform your manager, designate an Alternate User, and submit your OOO dates in Salesforce. Failure to do this results in MQLs breaching SLA — which escalates to your FLM and VP in Slack. Hand Raisers in breach escalate within 24 hours.", resource: { label: "TOFU FAQ — What Happens if I'm Going on PTO?", url: DAY2_TOFU_FAQ } },
  { id: 5, type: "mc", lo: "LO2", text: "An AE receives a Product Signal MQL for a contact at an existing customer account. The contact's title is 'Data Engineer' and the trigger is a product overage alert. The AE marks it 'No Pain' and disqualifies it. What's wrong with this decision?", options: ["Nothing — a Data Engineer isn't a buyer, so there's no commercial value in pursuing this MQL","Product Signal MQLs from existing customers should always be routed to the CSM, not worked by the AE","A product overage is a direct signal of usage growth and potential expansion — 'No Pain' is the wrong disqualification. The right move is to accept, reach out, and explore whether the overage signals a need to expand the contract or add products.","The AE should have rerouted this to an SDR — customer MQLs are SDR territory"], correct: 2, explanation: "Product Signal MQLs from customers are some of the most valuable inbounds — they indicate active usage and potential pain. A product overage is a direct signal that the customer has grown beyond their current contract. 'No Pain' means there is no use case for Amplitude — that's clearly not true here. Customer MQLs route to AEs specifically because the AE owns the commercial relationship. Disqualifying this without investigation is a missed expansion opportunity.", resource: { label: "TOFU Training Deck — New MQL Types (Product Signals)", url: DAY2_TOFU_DECK } },
  { id: 6, type: "match", lo: "LO1", text: "Match each MQL type to its correct description and priority level.", pairs: [{ term: "Hand Raiser", match: "Highest priority — prospect directly requested contact (e.g. Contact Sales, Experiment Upgrade Request)" },{ term: "Product Signal", match: "Second priority — paying or non-paying user showing usage signals (e.g. overage, new demo signup, plan expiring)" },{ term: "Other / Event MQL", match: "Third priority — engaged with marketing content or events (e.g. ebook download, webinar, conference)" }], correct: 0, explanation: "MQL priority exists so reps know where to focus first. Hand Raisers have the highest intent — they asked to be contacted — so they get the shortest SLAs (1-2 hours depending on segment). Product Signals indicate active product engagement and often signal expansion or upgrade conversations. Other MQLs show awareness but lower purchase intent. Prioritizing in this order maximizes conversion.", resource: { label: "TOFU Training Deck — New MQL Types", url: DAY2_TOFU_DECK } },
  { id: 7, type: "mc", lo: "LO3", text: "You have 4 open MQLs at the same time: a Hand Raiser from a net new prospect (2-hour SLA), a Product Signal from a customer (16-hour SLA), an Other MQL from a conference attendee (24-hour SLA), and a Hand Raiser from a net new prospect that came in 90 minutes ago. In what order do you work them?", options: ["Oldest first regardless of type — first in, first out is the fairest approach","The Hand Raiser that came in 90 minutes ago first (30 minutes left on SLA), then the new Hand Raiser, then the Product Signal, then the conference attendee","Both Hand Raisers first (tie — work in order received), then Product Signal, then Other MQL","Hand Raisers first by highest person score, then Product Signal, then Other MQL — all in order of score within type"], correct: 1, explanation: "The 90-minute-old Hand Raiser has 30 minutes left on the clock — that's the immediate priority. A breach escalates to your FLM. After that, address the new Hand Raiser (which has its own 2-hour clock running). Then the Product Signal, then the conference attendee. When SLA timers are running simultaneously, triage by urgency within type, not just by type alone. Monitoring your SLA dashboard in Tableau helps you avoid this kind of crunch.", resource: { label: "TOFU Training Deck — Time to First Touch SLAs", url: DAY2_TOFU_DECK } },
  { id: 8, type: "fill", lo: "LO1", text: "A contact in the SAL stage with no logged activity in 30 days and whose last activity was more than 10 business days ago will be automatically ________ by the system.", correct: ["disqualified","auto-disqualified","automatically disqualified","DQ'd","DQ"], placeholder: "what happens to them...", explanation: "The inactivity threshold for SAL stage is 30 days with no activity and last activity over 10 business days ago. Contacts that hit this threshold are automatically disqualified with reason 'Inactivity' and enter a 30-day cool-off before marketing can nurture them back into the funnel. This is by design — keeping stale contacts in your pipeline obscures your true pipeline health and wastes everyone's time.", resource: { label: "TOFU Training Deck — Inactivity Thresholds", url: DAY2_TOFU_DECK } },
  { id: 9, type: "mc", lo: "LO3", text: "A prospect disqualified with reason 'Competitor' comes back 25 days later and completes a Contact Sales form. What happens?", options: ["They remain disqualified — once a competitor flag is on a record it doesn't automatically clear","They bypass the 30-day cool-off because Hand Raisers supersede cool-off periods — they'll immediately re-MQL and route back to the same owner","They re-enter the funnel after the 30-day cool-off period expires — since 25 days haven't passed yet, they stay in nurture","They route to the SDR team for qualification since the AE already lost this deal once"], correct: 1, explanation: "Hand Raisers supersede cool-off periods — full stop. It doesn't matter if the contact was disqualified yesterday with a 90-day cool-off. If they submit a Contact Sales form, that's a Hand Raiser and they immediately re-MQL. This is intentional: someone raising their hand to speak to Amplitude is the highest-priority inbound signal. The cool-off periods exist for nurture sequences — they don't block a genuine inbound request.", resource: { label: "TOFU Training Deck — Cool Off Periods (Hand Raisers Supersede)", url: DAY2_TOFU_DECK } },
  { id: 10, type: "mc", lo: "LO3", text: "Your manager asks you to pull your MQL performance numbers for your weekly 1:1. Where do you go and what metrics should you know?", options: ["The MQL Prioritization Dashboard in SFDC — it shows your open MQLs and SLA status in real time","The GTM Launchpad TOFU Sales tab, which links to your Sales Performance Dashboard in Tableau — review SLA adherence rates, MQL counts, and MQL-to-opportunity conversion rates","Your Outreach sequence performance reports — they track email open rates and reply rates tied to MQL follow-up","The Revenue Console MQL list view — sort by status to manually count your accepted vs disqualified MQLs"], correct: 1, explanation: "The Sales Performance Dashboard in Tableau — accessed through the TOFU Sales tab on the GTM Launchpad — is the authoritative source for your TOFU metrics. The MQL Prioritization Dashboard is explicitly deprecated. The Tableau dashboard shows: number of MQLs assigned, SLA compliance rate, conversion metrics, and team comparisons. Your FLM reviews this in your 1:1 — knowing your own numbers before the conversation is expected.", resource: { label: "TOFU FAQ — How Do I Track My Performance?", url: DAY2_TOFU_FAQ } },
];

const DAY3_GTM = "https://docs.google.com/presentation/d/1tm_q5TJVRNYRrIB6wc5AGSmqTWyFDi3Na1EwO8tp80M/edit";
const DAY3_TOFU_FAQ = DAY2_TOFU_FAQ;

const v1Day3 = [
  { id: 1, type: "mc", lo: "LO1", text: "The GTM Launch Pad is organized into three main sections. Which of the following best describes what each section is for?", options: ["Pipeline, Forecast, and Renewal — each section tracks a different stage of the deal cycle","Business Reviews, Prospecting, and Customers — Business Reviews shows pipeline and forecast data, Prospecting helps prioritize net new accounts and contacts, and Customers surfaces expansion and risk signals for existing accounts","TOFU, MOFU, and BOFU — tracking lead generation, deal progression, and close management","SDR, AE, and FLM views — each section is filtered by role so individuals only see data relevant to their job function"], correct: 1, explanation: "The GTM Launch Pad has three sections: Business Reviews (pipeline generation, pipeline execution, coverage, forecasting, renewal readiness), Prospecting (which accounts to target, which contacts to prioritize, Starter/Scholarship/Plus plan signals, partner overlaps, MTU-based targeting), and Customers (expansion candidates, account risk signals, product whitespace). These three sections together give you a full picture of your territory — net new and existing.", resource: { label: "GTM Launch Pad Slides — RtB Dashboard Overview", url: DAY3_GTM } },
  { id: 2, type: "mc", lo: "LO2", text: "You're preparing for a territory planning session with your manager. You want to identify which of your existing customers are prime expansion candidates and which are at risk. Which section of the GTM Launch Pad do you use, and what specifically are you looking for?", options: ["Prospecting section — filter by existing customer accounts to find upsell signals and flag any with declining MTU trends","Business Reviews section — the Pipeline Review tab shows all your open opportunities including expansion, so you can sort by deal size","Customers section — look for accounts flagged as expansion-ready, review product whitespace (which products they have vs. which they're a fit for), and check risk signals to align with CS before renewal","Forecasting section — accounts with 'at risk' tags will surface here alongside your commit and upside categories"], correct: 2, explanation: "The Customers section of the GTM Launch Pad is built specifically for this. It shows: which customers are prime for expansion, risk signals associated with accounts, and product whitespace — which products clients are using and which ones they're a fit for but haven't bought yet. This is the data that drives expansion strategy and CS alignment. Using it weekly keeps you ahead of risks instead of reacting to them.", resource: { label: "GTM Launch Pad Slides — RtB: Customer Overview", url: DAY3_GTM } },
  { id: 3, type: "mc", lo: "LO2", text: "An AE is preparing for a Monday morning prospecting session. They open the GTM Launch Pad and go directly to the Business Reviews section to find accounts to target. What's wrong with their approach?", options: ["Nothing — Business Reviews is the best starting point for prospecting because it shows pipeline coverage gaps that indicate which territories need more top-of-funnel activity","They should be in the Prospecting section, which is specifically built to surface which accounts to target, which contacts to prioritize within those accounts, and which accounts show signals like Starter plan usage or partner overlap","They should use Outreach for prospecting, not the GTM Launch Pad — the Launch Pad is for managers, not ICs","They should start with the Customers section to look for expansion signals before pursuing net new accounts"], correct: 1, explanation: "The Prospecting section of the GTM Launch Pad is designed precisely for this use case: prioritizing which accounts to target, which contacts to go after within those accounts, which accounts are on free/starter plans worth converting, partner account identification, and MTU-based targeting. Business Reviews is for pipeline and forecast review, not prospecting prioritization. Using the wrong section wastes time and misses the intent signals built into the tool.", resource: { label: "GTM Launch Pad Slides — RtB: Prospecting Overview", url: DAY3_GTM } },
  { id: 4, type: "tf", lo: "LO1", text: "True or False: You should use the GTM Launch Pad directly to work MQLs and action leads.", options: ["True","False"], correct: 1, explanation: "This is explicitly called out in the TOFU training: 'Do NOT work leads directly from the dashboard.' The GTM Launch Pad is a reporting and insight tool — it shows MQL progress data, SLA adherence, and funnel metrics. You use it to understand performance and prioritize. The Revenue Console app with the 'My MQLs' contact list view is where you actually take action on leads.", resource: { label: "TOFU FAQ — A seller should use the GTM Launch Pad primarily for reviewing MQL progress reports. Do not work leads directly from the dashboard.", url: DAY3_TOFU_FAQ } },
  { id: 5, type: "mc", lo: "LO3", text: "Your manager asks you to come to your 1:1 ready to discuss pipeline coverage and territory health. You open the GTM Launch Pad and pull up the Prospecting section. What's wrong with this preparation?", options: ["Nothing — the Prospecting section shows your entire territory so coverage is visible there","You should be in the Business Reviews section, which covers pipeline generation, pipeline execution, deals in play, coverage ratios, and anything related to new business performance — that's the right view for a pipeline and territory health conversation","You should use Outreach's pipeline view instead of the GTM Launch Pad for this conversation","You need CRMA access to view pipeline data — if you haven't requested it, you won't see the right metrics"], correct: 1, explanation: "Pipeline coverage and territory health live in the Business Reviews section — not Prospecting. Business Reviews covers pipeline generation, pipeline execution, coverage ratios, deals in play, and anything related to new business performance. Coming to your 1:1 with the Prospecting view open signals you don't know how to navigate the tool — and your FLM will know it. Understand which section maps to which business question before the meeting.", resource: { label: "GTM Launch Pad Slides — RtB: Business Overview", url: DAY3_GTM } },
  { id: 6, type: "mc", lo: "LO3", text: "You notice in the GTM Launch Pad's Customers section that one of your accounts has a high expansion score but your CSM hasn't flagged any upsell opportunity. The account's current contract is up for renewal in 5 months. How should you use this insight?", options: ["Reach out to the customer directly to pitch the expansion — the Launch Pad signal is enough to justify the conversation without involving CS","Ignore it until the CSM flags it — the CSM owns the customer relationship and will know when to surface expansion opportunities","Bring the expansion signal to your CSM now — use the whitespace data to align on a joint expansion strategy and start the conversation with the customer well before renewal creates urgency and price pressure","Create a Salesforce opportunity immediately to claim credit for the expansion before anyone else spots the signal"], correct: 2, explanation: "This is exactly what the Customers section is built for — surfacing expansion signals early so you can act proactively. The right move is to take the insight to your CSM and align on strategy before the renewal window creates pressure. AE-CS alignment on expansion is part of the pod model. Acting alone without CS context risks damaging the relationship. Waiting for the CSM to flag it costs you months of runway. Five months out is a comfortable position — don't let it become a fire drill.", resource: { label: "GTM Launch Pad Slides — RtB: Customer Overview (Expansion & Risk Signals)", url: DAY3_GTM } },
  { id: 7, type: "mc", lo: "LO1", text: "You need CRMA access to use the GTM Launch Pad. How do you request it?", options: ["Email your FLM and ask them to submit an IT ticket on your behalf","Submit a request directly through IT helpdesk","Go to Lumos in Slack, submit a Custom Request with justification: need CRMA to access the SFDC Launch Pad dashboard","Post in #help-salesops and Sales Ops will provision access within one business day"], correct: 2, explanation: "CRMA access is requested through Lumos in Slack — the standard tool provisioning platform at Amplitude. The path is: Lumos in Slack → Which app do you need? → Custom Request → Justification: need CRMA in order to access SFDC Launch Pad dash. Not having CRMA access means you can't use the GTM Launch Pad at all — this is a Day 1 setup item.", resource: { label: "GTM Launch Pad Slides — CRMA Access via Lumos", url: DAY3_GTM } },
  { id: 8, type: "fill", lo: "LO1", text: "The GTM Launch Pad's Prospecting section includes a view for identifying accounts to target based on ________ (Monthly Tracked Users), a key metric for understanding an account's Amplitude usage potential.", correct: ["MTUs","MTU","Monthly Tracked Users","monthly tracked users"], placeholder: "what metric...", explanation: "Monthly Tracked Users (MTUs) is one of Amplitude's core pricing and value metrics. The Prospecting section of the GTM Launch Pad lets you filter and target accounts based on MTU data — understanding their current usage scale helps prioritize which accounts have the most growth potential or are most likely to be in a position to expand.", resource: { label: "GTM Launch Pad Slides — RtB: Prospecting Overview (MTUs)", url: DAY3_GTM } },
  { id: 9, type: "mc", lo: "LO3", text: "In the Prospecting section, you see that three accounts in your territory are on Starter plans. A fourth has a Scholarship plan. What does this signal and how should you approach these accounts differently from cold prospects?", options: ["These are customers — they should be handled by the CS team, not prospected by the AE","These accounts already have hands-on Amplitude experience — they're warmer than cold outreach targets. Starter and Scholarship accounts show product engagement signals. Use the Launch Pad data to understand their usage level and approach with a conversation about what they're already getting value from versus what they're missing at their current plan tier.","Starter and Scholarship accounts typically have no budget — deprioritize them in favor of accounts with no existing relationship","Treat them the same as cold prospects — the fact that they're on a free plan means they haven't committed and the relationship isn't meaningful yet"], correct: 1, explanation: "Starter and Scholarship accounts are warm signals — these companies have chosen to use Amplitude and are getting value from it at some level. That's a different conversation than cold outreach. The GTM Launch Pad specifically surfaces these accounts in the Prospecting section as conversion candidates. Your approach should be consultative: understand what they've built, surface what they can't do at their current tier, and show the path to more value. They're not customers yet, but they're not strangers either.", resource: { label: "GTM Launch Pad Slides — RtB: Prospecting (Starter/Scholarship/Plus Plans)", url: DAY3_GTM } },
  { id: 10, type: "mc", lo: "LO1", text: "Where do you go if you have questions about the GTM Launch Pad or the Run the Business dashboards?", options: ["#help-salesops","#sales-run-the-business-dashboard","Email Matt Kahan directly","#help-IT"], correct: 1, explanation: "The dedicated Slack channel for GTM Launch Pad and Run the Business dashboard questions is #sales-run-the-business-dashboard. This is where Matt Kahan and the sales operations team field questions. #help-salesops is for broader sales operations questions, and #help-IT is for technical access issues. Using the right channel gets you a faster answer from the right person.", resource: { label: "GTM Launch Pad Slides — Resources & Questions (#sales-run-the-business-dashboard)", url: DAY3_GTM } },
];

const DAY4_PROSPECTING = "https://docs.google.com/presentation/d/12u9LXd4vnyNQrv9d6hB2CjrppGNUYNpxCbFRnFKAJjw/edit";

const v1Day4 = [
  { id: 1, type: "mc", lo: "LO1", text: "You're building a ZoomInfo search to identify Product Decision Makers at target accounts. You want to filter for people who could champion an Amplitude purchase. Which of the following job title categories should you target?", options: ["Chief Technology Officer, VP Engineering, Head of Infrastructure — these roles control the tech stack and own the buying decision","Product Manager, VP of Product, Head of Product, Chief Product Officer — Amplitude's product persona is the core user and often the champion for analytics purchases","Chief Revenue Officer, VP Sales, Head of Revenue Operations — they care about pipeline and conversion data most","Chief Financial Officer, VP Finance, Head of FP&A — they control the budget and are the economic buyer on analytics deals"], correct: 1, explanation: "Amplitude's Product Decision Maker buying group includes roles like Product Manager, VP of Product, Head of Product, and CPO. These are the primary users and champions — they're the ones with the pain (not knowing which features drive retention, not being able to validate roadmap decisions quickly) and the motivation to own an analytics platform. Amplitude has pre-built ZoomInfo job title lists for each buying group — Product, Data/Analytics, Marketing — that you can copy and paste directly into the bulk job title field.", resource: { label: "Prospecting Process Deck — Land Accounts: Buying Groups (Product Decision Makers)", url: DAY4_PROSPECTING } },
  { id: 2, type: "mc", lo: "LO2", text: "You find a strong target contact in ZoomInfo and export them to Salesforce. What are the two required steps after export before you start outreach?", options: ["Enrich the contact in ZoomInfo and add them to a Salesforce campaign for tracking","Check that the contact isn't already in an active opportunity, then assign them to an Outreach sequence immediately","Tag every contact with your first and last name on export, then import to Outreach from the 'My ZoomInfo Contacts' list view in Salesforce","Validate the email address manually and create a Salesforce opportunity before placing them in a sequence"], correct: 2, explanation: "Two required steps: (1) tag every contact you add or enrich with your first and last name — this is mandatory for ownership tracking and data hygiene. (2) Import to Outreach from the 'My ZoomInfo Contacts' list view on the Salesforce Contacts tab. Sales Navigator can be used for optional research between export and engagement, but it's not required. Missing the tag creates attribution problems and data quality issues downstream.", resource: { label: "Prospecting Process Deck — Land Accounts: Export to SFDC & Tag Contacts", url: DAY4_PROSPECTING } },
  { id: 3, type: "mc", lo: "LO2", text: "You're prospecting into a target account and want to use LinkedIn Sales Navigator to research the buying group before reaching out. Which Sales Navigator features are most relevant for this purpose?", options: ["InMail and Advanced Search — send a personalized InMail directly to each contact before touching email","Account IQ, Relationship Maps, Intent Signals, and Best Path In — these help you understand the account structure, identify warm connections, and find the most efficient entry point before you start outreach","Saved Leads and Alerts only — set up account alerts and wait for job change or growth signals before initiating contact","Personas — create a custom persona filter and let Sales Navigator auto-identify all contacts to import to SFDC"], correct: 1, explanation: "For research and validation before outreach, Account IQ gives you company-level intelligence, Relationship Maps show internal org structure and warm connection paths, Intent Signals surface buying behavior, Best Path In identifies the easiest entry point through mutual connections, and InMail gives you a direct channel to prospects. Sales Navigator is described as a research and validation tool — use it to make your outreach smarter, not to replace it. Note: you have 50 InMail credits per month (capped at 150), so use them strategically.", resource: { label: "Prospecting Process Deck — Know Your Tech Stack: LinkedIn Sales Navigator", url: DAY4_PROSPECTING } },
  { id: 4, type: "tf", lo: "LO1", text: "True or False: You receive 1,000 ZoomInfo credits per month. Unused credits roll over to the next month, so you can save them up for a big prospecting push.", options: ["True","False"], correct: 1, explanation: "ZoomInfo credits do NOT roll over — you get 1,000 per month and they reset on the 1st. This means you should be using ZoomInfo consistently throughout the month, not saving up for a big push. Also critical: if you don't log in within 30 days, your license can be reassigned. Use it or lose it — both the credits and the license.", resource: { label: "Prospecting Process Deck — ZoomInfo Credits & Usage (1,000 per month, no rollover)", url: DAY4_PROSPECTING } },
  { id: 5, type: "mc", lo: "LO3", text: "An AE is running a cold outbound campaign to 50 contacts at the same company. They plan to send one email per contact per day using Outreach. What's the problem?", options: ["Nothing — 50 emails is within the daily sending limit","Outreach limits you to 18 emails per day per domain, shared across all reps (not per user). Sending 50 emails to a single company's domain in one day will cap out after 18 and the rest won't send — and your SDR counterpart's emails to that same domain count against that limit too.","The issue is the sequence length — Outreach limits sequences to 10 steps so 50 contacts would require five separate sequences","You can only send 5 emails per day total per rep in Outreach, so 50 contacts would take 10 days minimum"], correct: 1, explanation: "The 18 emails/day per domain limit is critical and often misunderstood. It's not per user — it's shared across ALL reps sending to that domain. If you and your SDR are both prospecting the same company, you're competing for the same 18 slots. This means coordinating on domain-heavy campaigns is essential. The individual limits are 500 emails/day per user and 5 emails/day per prospect — but the domain limit is the binding constraint for concentrated account campaigns.", resource: { label: "Prospecting Process Deck — Daily Usage & Limitations (18 emails/day/domain)", url: DAY4_PROSPECTING } },
  { id: 6, type: "match", lo: "LO1", text: "Match each prospecting tool to its primary purpose at Amplitude.", pairs: [{ term: "ZoomInfo", match: "B2B contact and company database — use for advanced search, filtering, exporting contacts to SFDC, buyer intent signals, and data enrichment" },{ term: "LinkedIn Sales Navigator", match: "Research and validation — use for Account IQ, relationship maps, InMail, intent signals, and finding best path into an account" },{ term: "Outreach", match: "Multi-channel engagement and pipeline management — use for sequences, tasks, call recording via Kaia, and prospect list views" },{ term: "GTM Launch Pad (Prospecting section)", match: "Territory prioritization — use pre-built list views for Amp Alumni, 6sense High Intent, and Interesting Moments contacts to identify who to target" }], correct: 0, explanation: "Each tool in the prospecting tech stack has a specific purpose. Mixing up their roles leads to duplicated effort and missed signals. ZoomInfo is for finding and exporting net new contacts. Sales Navigator is for research and validation before outreach. Outreach is for multi-channel engagement execution. The GTM Launch Pad Prospecting section is for prioritizing who to go after using Amplitude's built-in signals.", resource: { label: "Prospecting Process Deck — Know Your Tech Stack Overview", url: DAY4_PROSPECTING } },
  { id: 7, type: "mc", lo: "LO3", text: "You've built a ZoomInfo search targeting Data Analytics Decision Makers at accounts with 500-5,000 employees in the B2B SaaS space. The search returns 1,200 results. What's the most efficient next step?", options: ["Export all 1,200 to Salesforce — you'll sort through them later when building Outreach sequences","Apply the pre-built buying group job title filters from the Prospecting Process training to narrow to relevant titles, then export only verified contacts at your target accounts","Sort by ZoomInfo intent score and only export the top 50 — quality over quantity","Share the search with your SDR and split the 1,200 contacts evenly for outreach"], correct: 1, explanation: "Amplitude has pre-built job title lists for each buying group (Product, Data/Analytics, Marketing). Use them as a filter layer on top of your company search to narrow from 1,200 to a targeted set. Then export only verified contacts at accounts you've already prioritized. Bulk exporting 1,200 contacts wastes credits, pollutes your Salesforce data, and overwhelms your Outreach capacity. Be surgical.", resource: { label: "Prospecting Process Deck — Land Accounts: Filtering with Buying Group Lists", url: DAY4_PROSPECTING } },
  { id: 8, type: "fill", lo: "LO1", text: "In Outreach, the daily email sending limit per prospect is ________ emails per day.", correct: ["5","five"], placeholder: "how many...", explanation: "The per-prospect daily email limit in Outreach is 5 emails per day. This is separate from the per-user limit (500/day) and the per-domain limit (18/day shared across all reps). The per-prospect limit is rarely the binding constraint, but it matters when you're running multi-step sequences with tight timing — ensure your sequence spacing respects this limit.", resource: { label: "Prospecting Process Deck — Daily Usage & Limitations (5 emails/day/prospect)", url: DAY4_PROSPECTING } },
  { id: 9, type: "mc", lo: "LO2", text: "You're setting up an Outreach sequence for a targeted campaign to VP-level contacts at 10 high-priority accounts. Which approach best applies the prospecting process training?", options: ["Create one generic sequence with 7 email touchpoints — scale is the priority and personalization can come later","Build a sequence that combines emails, LinkedIn connection requests, and phone tasks — multi-channel engagement is the standard. Personalize the first touchpoint per account using insights from Sales Navigator and the GTM Launch Pad.","Create separate sequences for each of the 10 accounts — each VP needs a fully custom cadence","Use a 3-email sequence with no phone or LinkedIn steps — VP-level contacts don't respond to calls or social outreach"], correct: 1, explanation: "The Prospecting Process training is explicit: Outreach is for multi-channel engagement. A modern sequence should include emails, LinkedIn touchpoints, and phone tasks. The first touchpoint to each VP should be personalized using account-level insights from Sales Navigator (Account IQ, recent signals) and the GTM Launch Pad (product signals, plan tier). Personalization at scale — not one-size-fits-all sequences or fully custom cadences for each account.", resource: { label: "Prospecting Process Deck — Multi-Channel Engagement via Outreach", url: DAY4_PROSPECTING } },
  { id: 10, type: "mc", lo: "LO1", text: "Where do you go if you have questions about ZoomInfo, Outreach, or Sales Navigator?", options: ["#help-salesops","#help-tools in Slack — the dedicated channel for sales tool questions and troubleshooting","Email the enablement team directly","Post in #general and tag your FLM"], correct: 1, explanation: "The dedicated Slack channel for sales tool questions — including ZoomInfo, Outreach, and Sales Navigator — is #help-tools. This is where the sales operations and enablement team field questions about tool access, configurations, and best practices. Using the right channel gets you a faster answer and keeps the knowledge searchable for others.", resource: { label: "Prospecting Process Deck — Resources & Support (#help-tools)", url: DAY4_PROSPECTING } },
];

const DAY5_CEM = "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit";
const DAY5_SPEKIT = "https://app.spekit.co/app/wiki/asset/817909a3-30d8-4b9b-9a35-d8c07150b365?type=asset&expanded=true";
const DAY5_SFDC = "https://amplitude.lightning.force.com/analytics/dashboard/0FKUw0000000eOrOAI";

const v1Day5 = [
  { id: 1, type: "mc", lo: "LO1", text: "According to the CEM, the renewal motion officially begins at Stage 2 Qualification — how many days before the renewal date does this stage start?", options: ["30 days out — that's when the AE is responsible for getting involved","90 days out — the standard window for renewal proposal delivery","180 days out — this is when account health, customer sentiment, adoption, and strategic alignment should be assessed and the renewal motion confirmed","60 days out — the proposal stage window"], correct: 2, explanation: "Per the CEM Renewal Motion, S2 Qualification begins at R-180 days. At this stage the AE and TSM conduct an internal renewal review, confirm EB/Champion, update the renewal forecast, and deliver the EBR. Starting 180 days out gives you time to identify risk early, course-correct adoption gaps, and shape the renewal before commercial pressure builds. Waiting until 90 or 60 days means you're reacting, not leading.", resource: { label: "Customer Engagement Model — Renewal Motion S2 (R-180 Days)", url: DAY5_CEM } },
  { id: 2, type: "mc", lo: "LO2", text: "At R-180, your renewal review reveals low product adoption across the customer's primary use cases. Applying Challenger thinking, what's the core problem and what does it tell you about the right response?", options: ["Low adoption is a price problem — a flexible renewal offer removes the financial barrier to continued investment","Low adoption is a CS problem — escalate to the TSM and let them manage the risk through the success plan","Low adoption is a value problem, not a price problem. The customer's status quo — unrealized outcomes — is costing them. Your job is to Teach what they're leaving on the table, deepen the pain of doing nothing, and lead toward a path to value. A discount without addressing adoption sets up a worse renewal next year.","Low adoption signals a poor product fit — explore whether Amplitude is actually the right solution before investing in the renewal"], correct: 2, explanation: "This is the Challenger 'pain of same' concept applied to renewals. Low adoption = unrealized value = the customer is paying for something they're not fully using. The right Challenger move is to Teach: surface what they're missing, quantify the cost of the status quo, and build a path to realized ROI. A discount without a value conversation solves the wrong problem — it just makes a cheaper version of the same risk. This is also why the AE and TSM must align at R-180, not wait until renewal pressure forces the conversation.", resource: { label: "Customer Engagement Model — Renewal Motion S2 (R-180 Days)", url: DAY5_CEM } },
  { id: 3, type: "mc", lo: "LO2", text: "Your customer's champion just left the company. Their replacement emails you asking to 'evaluate whether to continue with Amplitude.' The TSM says usage metrics look healthy. How does the CEM define your responsibility at this point?", options: ["Route the email to the TSM — stakeholder changes are a CS responsibility at this stage","This is a Mobilizer identification moment. The new stakeholder hasn't been Taught the value narrative — they're evaluating from a blank slate. Per the CEM, the AE is responsible for confirming EB/Champion at S2. Engage immediately, treat this like re-opening the sale, and determine if this person can be a renewal champion.","Wait for the official renewal stage to begin before re-engaging — acting too early could create commercial pressure before you're ready to propose","Send a usage report to let the data make the case — healthy metrics are your strongest asset in this conversation"], correct: 1, explanation: "Per the CEM, AE responsibilities at S2 include confirming Champion and EB. A champion departure resets this requirement. The Challenger insight here: this new stakeholder has no relationship with Amplitude, no loyalty to the existing contract, and the authority to change course. Healthy usage data is supporting evidence — it's not a substitute for a value conversation. Treat this as a re-sale. Reach out immediately, bring a commercial insight, and qualify whether they can champion the renewal internally.", resource: { label: "Customer Engagement Model — Renewal Motion S2 AE Responsibilities (Confirm EB/Champion)", url: DAY5_CEM } },
  { id: 4, type: "match", lo: "LO1", text: "Match each CEM Renewal stage to the milestone that triggers it and the key AE activity at that stage.", pairs: [{ term: "S2 Qualification (R-180)", match: "Confirm EB/Champion, deliver EBR, update renewal forecast, confirm renewal motion (flat/expansion/churn)" },{ term: "S3 Business & Technical Evaluation (R-120)", match: "Hold Renewal Readiness Call, draft Renewal MAP, qualify expansion, confirm decision process" },{ term: "S5 Proposal (R-60)", match: "Deliver Renewal Proposal, confirm EB/Champion intent to renew, update MAP with contracting steps" },{ term: "S6 Negotiation (R-30)", match: "Manage commercial redlines, legal review, PO/procurement management, FLM/exec escalation if needed" }], correct: 0, explanation: "The CEM Renewal Motion is a staged process with clear owner activities at each milestone. S2 at R-180 is the planning stage — confirm who owns the renewal decision and what motion you're running. S3 at R-120 is the alignment stage — get the Renewal MAP in place and surface expansion opportunities. S5 at R-60 is the proposal stage — formal renewal terms on the table. S6 at R-30 is the closing stage — remove commercial and legal friction. AEs who know these stages avoid last-minute fire drills.", resource: { label: "Customer Engagement Model — Renewal Motion Stage-by-Stage AE Activities", url: DAY5_CEM } },
  { id: 5, type: "mc", lo: "LO2", text: "A customer pushes back with a 30% discount request at R-60, citing budget pressure. You're at S5 in the renewal motion. What's the Challenger-grounded response according to both the CEM and the Sales Policy Handbook?", options: ["Offer a partial discount — 15% is within policy and shows good faith on pricing","Hold firm on price — discounting at renewal creates a compounding precedent that gets worse every year","Understand the root cause before reacting. A discount request is a symptom. Is this genuine budget pressure, low adoption (a value problem), a competitive threat, or a negotiating tactic? Each requires a different response. Going to Deal Desk with a number before you know the cause gives up leverage you can't recover.","Escalate to your FLM immediately — any discount above 10% requires approval so loop them in before responding"], correct: 2, explanation: "The Sales Policy Handbook governs discount guardrails — but before any discount conversation, Challenger methodology says: investigate the frame. A 30% request is not a budget problem until you've confirmed it. If it's really low adoption (value problem), no discount solves that — the customer renews at a discount and churns next year anyway. If it's a competitive threat, you need to know who. If it's a negotiating tactic, you've just anchored unnecessarily low. Diagnose before you respond. That's both good deal-making and what the CEM Renewal Motion asks for at S5.", resource: { label: "2026 Sales Policy Handbook (Spekit) — Renewal Pricing Guardrails", url: DAY5_SPEKIT } },
  { id: 6, type: "tf", lo: "LO3", text: "True or False: If the TSM is managing the account health and success plan, the AE does not need to be involved in the renewal until the Proposal stage (R-60).", options: ["True","False"], correct: 1, explanation: "The CEM is explicit: AE involvement in renewals starts at R-180. At S2, the AE confirms EB/Champion, updates the forecast, and co-delivers the EBR with the TSM. At S3, the AE drafts the Renewal MAP and qualifies expansion opportunities. Waiting until R-60 means you're entering commercial negotiations without any of the groundwork — no MAP, no confirmed stakeholders, no value story established. The TSM manages the technical and adoption side; the AE owns the commercial thread. Both must be running in parallel from R-180.", resource: { label: "Customer Engagement Model — Renewal Motion S2 AE Responsibilities", url: DAY5_CEM } },
  { id: 7, type: "mc", lo: "LO1", text: "You're shaping a renewal that involves a pricing uplift, a term extension from 1 to 3 years, and adding a new product. What teams must be aligned, and what governs the discount and pricing thresholds?", options: ["Just your FLM — they have approval authority across pricing, term, and product additions","CS for adoption context, Deal Desk for pricing and quote approval per the Sales Policy Handbook, Finance for uplift and term policy, and Legal if MSA terms require updating. The 2026 Sales Policy Handbook governs discount guardrails and uplift expectations.","Deal Desk only — they're the single point of coordination for complex renewals","CS and Finance — CS owns the relationship and Finance owns the policy; Legal and Deal Desk only engage at the paper stage"], correct: 1, explanation: "A renewal with uplift, term extension, and new product touches multiple teams with distinct responsibilities. CS surfaces adoption context and value data. Deal Desk structures the quote and manages approval workflows per the 2026 Sales Policy Handbook. Finance owns uplift and term policy guardrails. Legal engages if MSA terms require modification. Renewals with this complexity are a team sport — missing any one of these creates delays or surprises at the finish line.", resource: { label: "2026 Sales Policy Handbook (Spekit) — Renewal Pricing Guardrails & Team Alignment", url: DAY5_SPEKIT } },
  { id: 8, type: "fill", lo: "LO1", text: "Where do you track renewal health, upcoming renewal milestones, and stage status across your book of business in Salesforce?", correct: ["Renewal Readiness Dashboard","renewal readiness dashboard","the Renewal Readiness Dashboard","SFDC Renewal Readiness Dashboard"], placeholder: "which dashboard...", explanation: "The Renewal Readiness Dashboard in Salesforce is your primary tool for tracking renewal status, health signals, and upcoming milestones. It's part of the GTM Launch Pad. Using it weekly means you're never surprised by an upcoming renewal — you're managing it proactively from R-180, not scrambling at R-30.", resource: { label: "Renewal Readiness Dashboard (SFDC)", url: DAY5_SFDC } },
  { id: 9, type: "mc", lo: "LO3", text: "A multi-risk account: low feature adoption, no executive sponsor in place, evaluating a competitor, and renewal is in 45 days. You're at S6. What should have happened at R-180 that would have prevented this situation?", options: ["An EBR with data showing platform ROI — if they had seen the numbers, they wouldn't be evaluating competitors now","At R-180 (S2), the AE and TSM should have conducted an internal renewal review, confirmed EB/Champion, delivered the EBR, and identified this account as a churn risk. A risk mitigation plan should have been built at S3 (R-120) with the TSM. By the time you're at R-45, these problems have typically been building for months — the CEM process exists precisely to catch them early.","A pre-emptive discount offer at R-120 to remove price as an objection before the competitor entered the conversation","Escalation to VP at R-90 — high-risk renewals should always have leadership involvement at this stage"], correct: 1, explanation: "This is a process failure that started at R-180. The CEM S2 Qualification requires: internal renewal review, confirmed Champion/EB, EBR delivery, and renewal motion determination — including churn risk. Low adoption + missing exec sponsor + competitor evaluation don't appear overnight. Each of these signals was visible earlier. The CEM's staged process exists to surface them with time to act. At R-45 with multiple compounding risks, your options are limited and expensive. The lesson: follow the process from R-180, not from R-60.", resource: { label: "Customer Engagement Model — Renewal Motion S2 (Why Process Matters at R-180)", url: DAY5_CEM } },
  { id: 10, type: "mc", lo: "LO3", text: "You close a renewal with a 3-year term, a 10% uplift, and no expansion. What is your primary responsibility immediately after the contract is signed, according to the CEM?", options: ["Update the closed-won opportunity in SFDC and move on to the next renewal in your pipeline","Complete the AE-to-TSM handoff document, introduce the TSM to the Champion/EB, create a placeholder success plan with the CSM, confirm kickoff details, and update SFDC with post-sale fields","Schedule a kickoff call with the customer to review the new contract terms and introduce the CS team","Send the customer a renewal confirmation email and tag your FLM in Slack to confirm booking"], correct: 1, explanation: "Per the CEM S6.5 Order Submitted stage, AE responsibilities after a closed renewal include: completing the AE→TSM handoff document, introducing the TSM to the Champion/EB, creating a placeholder success plan with the CSM, confirming kickoff details, and updating SFDC with all post-sale fields. This handoff is where the next renewal cycle begins — a clean handoff with documented context is what separates a smooth CS engagement from a rocky implementation that creates next year's renewal risk.", resource: { label: "Customer Engagement Model — Renewal Motion S6.5 Order Submitted AE Responsibilities", url: DAY5_CEM } },
];

const DAY6_COMPETITIVE = "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit";

const v1Day6 = [
  { id: 1, type: "mc", lo: "LO1", text: "Amplitude categorizes its competitive landscape into three tiers. Which of the following best describes Tier 1 competitors?", options: ["Emerging players who compete on price in specific verticals","Companies we encounter in most deals that compete directly across our core use cases — Mixpanel, Pendo, and Heap","Legacy analytics platforms (Google Analytics, Adobe) that are being replaced in the market","CDPs and experimentation tools that overlap with Amplitude's add-on products"], correct: 1, explanation: "Tier 1 competitors are those we encounter in most competitive deals and compete directly across Amplitude's core value propositions. Mixpanel, Pendo, and Heap are Tier 1: each has meaningful market presence, overlapping ICP, and positioned product capabilities. Tier 2 (Fullstory, PostHog, etc.) compete on narrower use cases. Tier 3 (Snowplow, in-house solutions) are lower frequency but real. Knowing the tier system helps you allocate competitive prep time efficiently.", resource: { label: "Competitive Landscape Deck — Competitive Tier Overview (T1/T2/T3)", url: DAY6_COMPETITIVE } },
  { id: 2, type: "mc", lo: "LO2", text: "You're in a competitive deal against Mixpanel. The prospect says: 'Mixpanel seems to do everything Amplitude does — and their pricing is simpler.' What's the Challenger response?", options: ["Agree on simplicity and pivot to Amplitude's enterprise features — governance, SSO, and role-based access will matter as they scale","Redirect to a technical deep-dive — once they see the behavioral analytics depth in Amplitude, the pricing concern will fade","Ask: 'When you say simpler, do you mean the list price or the total cost of ownership? Have you factored in implementation, integration maintenance, and what happens when your team outgrows the platform's analysis capabilities?' Reframe pricing from list price to business value and total cost of ownership.","Match the Mixpanel pricing — get Deal Desk involved to propose a competitive discount"], correct: 2, explanation: "When a prospect says 'simpler pricing,' they're comparing list prices — not total cost of ownership. The Challenger move is to reframe: total cost includes implementation time, integration maintenance, analyst productivity (how many questions can your team answer without filing a ticket?), and platform scalability. Amplitude's competitive positioning against Mixpanel focuses on depth of insight, enterprise scalability, and portfolio breadth. A discount without reframing the value equation just validates their frame.", resource: { label: "Competitive Landscape Deck — Mixpanel Competitive Positioning", url: DAY6_COMPETITIVE } },
  { id: 3, type: "match", lo: "LO1", text: "Match each Tier 1 competitor to Amplitude's primary competitive positioning against them.", pairs: [{ term: "Mixpanel", match: "Depth of behavioral analytics, portfolio breadth (CDP, Experimentation, Session Replay), enterprise scale and governance" },{ term: "Pendo", match: "Analytics depth and flexibility vs. Pendo's in-app guidance focus — Amplitude does analytics deeper, Pendo does in-app engagement" },{ term: "Heap", match: "Analysis power and enterprise trust — Heap captures everything automatically but struggles with large-scale query performance and enterprise governance" }], correct: 0, explanation: "Competitive positioning is about contrast, not feature comparison. Against Mixpanel: we go deeper analytically and offer a broader platform. Against Pendo: we're the analytics engine while Pendo leads with in-app guides — different primary use cases. Against Heap: auto-capture is Heap's strength but it creates noise at scale; Amplitude's structured approach delivers better query performance and enterprise trust. Know the contrast for each T1 — don't memorize feature matrices.", resource: { label: "Competitive Landscape Deck — Tier 1 Competitive Positioning", url: DAY6_COMPETITIVE } },
  { id: 4, type: "mc", lo: "LO2", text: "A prospect is evaluating both Amplitude and Pendo. They say: 'We really need in-app guides and surveys — Pendo includes that natively.' How should you position Amplitude?", options: ["Concede the in-app guidance use case — Pendo is better for that. Focus on analytics depth as the differentiator.","Acknowledge Pendo's in-app guidance strength and position Amplitude's Guides & Surveys add-on as the response — but lead with this: Amplitude gives them the analytics foundation to know WHAT to guide users toward. Without understanding user behavior deeply, in-app guides are guessing.","Tell them Amplitude has in-app guides too and they should compare feature-for-feature in a bake-off","Suggest they buy both — Pendo for guides and Amplitude for analytics. The platforms can coexist."], correct: 1, explanation: "This is a positioning move, not a feature war. Pendo's strength is in-app guidance — that's real. But guides without analytics depth are uninformed interventions. Amplitude's Guides & Surveys add-on provides the tactical capability, but the strategic differentiator is behavioral analytics: you can't guide users effectively if you don't deeply understand where they struggle, where they succeed, and what drives retention. Lead with the insight, not the feature.", resource: { label: "Competitive Landscape Deck — Pendo Competitive Positioning", url: DAY6_COMPETITIVE } },
  { id: 5, type: "mc", lo: "LO3", text: "A Head of Data Engineering at a prospect says: 'We're looking at Heap because auto-capture means we don't have to instrument events manually — our engineering team is already stretched thin.' How do you handle this objection?", options: ["Agree that auto-capture reduces engineering effort and pivot to Amplitude's other strengths","Tell them auto-capture captures too much data and creates noise — structured instrumentation is always better","Acknowledge the appeal of auto-capture for speed, then ask: 'What happens when your product changes and auto-captured selectors break? How confident are you in the data quality of retroactively defined events versus intentionally instrumented ones? At enterprise scale, auto-capture creates a different engineering burden — data cleaning and validation instead of upfront instrumentation.'","Suggest they use Heap for data collection and Amplitude for analysis — the tools can be integrated"], correct: 2, explanation: "Auto-capture is genuinely appealing — it removes the upfront instrumentation cost. But the Challenger move is to surface the hidden cost: auto-capture creates fragile data dependencies (CSS selectors break when the UI changes), retroactively defined events lack the semantic clarity of intentionally instrumented ones, and at scale the data cleaning burden shifts from engineering to analytics. You're not dismissing auto-capture — you're asking them to think about total cost of data quality.", resource: { label: "Competitive Landscape Deck — Heap Competitive Positioning (Auto-Capture Tradeoffs)", url: DAY6_COMPETITIVE } },
  { id: 6, type: "tf", lo: "LO1", text: "True or False: PostHog is a Tier 1 competitor to Amplitude.", options: ["True","False"], correct: 1, explanation: "PostHog is Tier 2, not Tier 1. Tier 1 competitors (Mixpanel, Pendo, Heap) are encountered in most competitive deals across Amplitude's core ICP. PostHog competes primarily in developer-centric and PLG-heavy environments — it's open-source, self-hosted by default, and targets teams that want to own their analytics infrastructure. It's real competition in specific segments but not a T1 across-the-board threat.", resource: { label: "Competitive Landscape Deck — Tier Classification (T1 vs T2 vs T3)", url: DAY6_COMPETITIVE } },
  { id: 7, type: "mc", lo: "LO3", text: "You discover mid-deal that the prospect has been doing a parallel evaluation with Snowplow (a Tier 3 competitor). You've never competed against Snowplow before. What's your first move?", options: ["Ignore it — Tier 3 competitors rarely win deals and aren't worth adjusting your strategy for","Check the competitive resources in Highspot for any existing Snowplow battlecards, and if none exist, use the #compete Slack channel to ask the competitive intelligence team for positioning guidance. Tier 3 competitors are lower frequency but can still win deals — especially when the prospect's use case aligns with the competitor's niche.","Immediately schedule a meeting with the competitive intelligence team to build a custom Snowplow battlecard for this deal","Treat Snowplow the same as a Tier 1 competitor and run the full competitive playbook — you can't afford to be unprepared"], correct: 1, explanation: "The #compete Slack channel and Highspot competitive resources are your two primary tools for competitive intelligence. Tier 3 competitors like Snowplow won't have the same depth of battlecard material as Tier 1, but the competitive intelligence team can provide positioning guidance for specific deal situations. Don't ignore it and don't over-invest — check existing resources first, then ask for targeted help if needed.", resource: { label: "Competitive Landscape Deck — Competitive Resources (Highspot & #compete)", url: DAY6_COMPETITIVE } },
  { id: 8, type: "fill", lo: "LO1", text: "The primary Slack channel for competitive intelligence questions, win/loss sharing, and real-time competitive positioning help at Amplitude is #________.", correct: ["compete","#compete"], placeholder: "channel name...", explanation: "The #compete Slack channel is the hub for competitive intelligence at Amplitude. Use it for: real-time positioning questions during active deals, win/loss sharing to build the competitive knowledge base, and requests for updated battlecard material. The competitive intelligence team monitors it actively. The faster you surface a competitive situation, the faster you get support.", resource: { label: "Competitive Landscape Deck — #compete Channel & Competitive Resources", url: DAY6_COMPETITIVE } },
  { id: 9, type: "mc", lo: "LO2", text: "A prospect says: 'We've already decided on Pendo for in-app guidance, but we're still evaluating analytics platforms. Can Amplitude integrate with Pendo?' What's the strategic opportunity here?", options: ["Yes — confirm the integration exists and position Amplitude as the analytics layer that makes Pendo's guides smarter. This is a Teach moment: show them that behavioral analytics data from Amplitude can inform which guides to deploy, when, and for which user segments.","No — tell them Amplitude and Pendo don't integrate, so they should reconsider their Pendo decision if they want a unified platform","Yes — but suggest they consider Amplitude's own Guides & Surveys instead of Pendo to consolidate their vendor stack","Defer the integration question to the SE and focus the conversation on analytics use cases only"], correct: 0, explanation: "This is a strategic positioning opportunity, not just a technical integration question. If the prospect has already decided on Pendo for guides, fighting that decision is a waste of leverage. Instead, position Amplitude as the analytics engine that makes Pendo more effective: which users need guidance? What behavior triggers should launch a guide? How do you measure whether a guide actually improved the user journey? Amplitude provides the intelligence layer that turns Pendo from a deployment tool into a precision tool.", resource: { label: "Competitive Landscape Deck — Coexistence Positioning (Analytics + Guidance)", url: DAY6_COMPETITIVE } },
  { id: 10, type: "mc", lo: "LO3", text: "You've just won a competitive deal against Heap. Your FLM asks you to share the win in #compete. What information is most valuable to include?", options: ["The discount you offered and the final deal size — this helps others benchmark pricing against Heap","The specific objections the prospect raised about Heap, what Amplitude capabilities sealed the deal, and any discovery insights about why the prospect ultimately chose Amplitude over Heap. Include what worked and what almost didn't.","A brief 'we won' announcement with the account name — the details can be discussed in the team meeting","The SE's technical comparison document — the bake-off results are the most useful artifact for future Heap deals"], correct: 1, explanation: "Win/loss sharing in #compete is most valuable when it includes the competitive dynamics: what objections came up, what positioning worked, what nearly lost the deal, and why the prospect chose Amplitude. This creates a searchable knowledge base that helps every AE facing Heap in the future. A simple 'we won' announcement has no learning value. Pricing details are sensitive but secondary to competitive positioning insights. The goal: make every Heap deal easier for the next rep.", resource: { label: "Competitive Landscape Deck — Win/Loss Sharing in #compete", url: DAY6_COMPETITIVE } },
];

const DAY7_ACCOUNT = "https://docs.google.com/presentation/d/1E6CvN9brHBGNkS2SZcslVNmaRyaiJhtvw4_Jrq-dJ2c/edit";
const DAY7_MOMENTUM = "https://docs.google.com/presentation/d/129YPTu9OKQYZM6fFIMxlsJOqalqUWcwlLvLnC4lOvXI/edit";

const v1Day7 = [
  { id: 1, type: "mc", lo: "LO1", text: "What is the primary purpose of a MAP (Mutual Action Plan) in the context of Amplitude's sales process?", options: ["A project management tool the AE uses internally to track deal milestones and tasks","A shared document between the AE and the customer that outlines the key steps, owners, and timelines required to reach a mutual decision — designed to create transparency, accountability, and shared commitment to the process","A legal document that outlines the terms of engagement before a contract is signed","A forecasting artifact that the FLM uses to validate deal stage accuracy in pipeline reviews"], correct: 1, explanation: "A MAP is a collaborative tool — not an internal tracking document. It lives between the AE and the customer, outlining who does what and by when to move toward a decision. The power of a MAP is shared accountability: the customer commits to steps (executive introductions, technical validation, procurement timelines), and the AE commits to deliverables (POV plans, pricing proposals, executive sponsorship). A MAP without customer ownership is just an internal project plan — and that's not the point.", resource: { label: "Account Planning Slides — Mutual Action Plan (MAP) Overview", url: DAY7_ACCOUNT } },
  { id: 2, type: "mc", lo: "LO2", text: "You're building an Account Plan for a target enterprise account. Which of the following best describes the Account Planning framework's view of what an Account Plan should accomplish?", options: ["Document the competitive landscape and product fit for each persona in the buying group","Align the AE's territory strategy with the FLM's forecast expectations — it's primarily a management alignment tool","Build a comprehensive view of the account: business objectives, key stakeholders, current tech stack, competitive threats, Amplitude's value proposition per persona, expansion opportunities, risks, and a concrete action plan with milestones and owners","Create a 90-day prospecting plan that outlines which contacts to engage and what sequences to run"], correct: 2, explanation: "An Account Plan per the framework is a complete strategic view of the account — not a prospecting plan or a management reporting artifact. It covers: what the customer is trying to achieve (business objectives), who matters (stakeholders and buying group mapping), what they're using today (tech stack and competitive landscape), how Amplitude adds value (per persona), where expansion exists, what risks are present, and what specific actions are planned with owners and deadlines. A good Account Plan is a living document that drives every interaction with the account.", resource: { label: "Account Planning Slides — What an Account Plan Should Cover", url: DAY7_ACCOUNT } },
  { id: 3, type: "mc", lo: "LO2", text: "You're preparing an Account Plan and need to map the buying group. Which stakeholder roles should you identify and document?", options: ["Champion and Economic Buyer only — those are the only two roles that matter in MEDDPICC","Champion, Economic Buyer, Technical Evaluator, Influencer, User Buyer, and any internal coaches who support your cause — the full buying group with each person's role, influence level, and disposition toward Amplitude","The C-suite only — enterprise deals are decided at the top and bottom-up influence is a myth","The procurement team and legal — those are the stakeholders who actually control the timeline and deal outcome"], correct: 1, explanation: "A complete buying group map includes every role that influences or decides the purchase: Champion (your internal advocate with power), Economic Buyer (final budget authority), Technical Evaluators (assess product fit), Influencers (shape opinions), User Buyers (end users who benefit), and Coaches (internal allies who share information). For each person, document their role, influence level, and disposition (for, against, or neutral). Missing a key stakeholder is one of the most common reasons enterprise deals stall or lose.", resource: { label: "Account Planning Slides — Buying Group Mapping", url: DAY7_ACCOUNT } },
  { id: 4, type: "match", lo: "LO1", text: "Match each Account Plan contributor to their primary contribution.", pairs: [{ term: "AE (Account Executive)", match: "Owns the Account Plan end-to-end, drives commercial strategy, manages stakeholder relationships, leads the MAP" },{ term: "SE (Solutions Engineer)", match: "Technical validation, POV design, product demonstration, competitive technical differentiation" },{ term: "TSM/CSM (Customer Success)", match: "Account health context, adoption data, renewal risk signals, success plan alignment" },{ term: "FLM (Front-Line Manager)", match: "Strategic coaching, deal review, escalation support, forecast validation, cross-functional coordination" }], correct: 0, explanation: "Account Planning is a team sport with clear role responsibilities. The AE owns the plan and drives execution. The SE provides technical depth and POV strategy. The TSM/CSM brings customer health and adoption intelligence. The FLM coaches the strategy, validates the plan in deal reviews, and provides escalation support. Each role contributes a different lens — the best Account Plans reflect all four perspectives.", resource: { label: "Account Planning Slides — Roles & Responsibilities in Account Planning", url: DAY7_ACCOUNT } },
  { id: 5, type: "mc", lo: "LO3", text: "An AE has an Account Plan for a key enterprise account but hasn't updated it in 3 months. The deal is in S3 and moving toward S5. What risk does this create?", options: ["Minimal risk — Account Plans are planning documents, not execution documents. The deal is progressing, so the plan has served its purpose.","Significant risk — a stale Account Plan means the AE may be working with outdated assumptions about stakeholders, competitive threats, business priorities, or decision criteria. The CEM requires stage-specific activities (MAP at S3, Proposal at S5) that should be reflected in a current plan. An outdated plan is a signal that the AE may be executing on momentum, not strategy.","Moderate risk — but only if the FLM hasn't reviewed the plan recently. If the FLM is tracking the deal, the plan doesn't need to be current.","No risk — the SFDC opportunity record is the source of truth for deal status, not the Account Plan"], correct: 1, explanation: "An Account Plan is a living document — not a one-time exercise. A 3-month gap in updates means stakeholder changes, competitive shifts, business priority evolution, and CEM stage requirements may all be missed. At S3, the AE should have a MAP drafted and expansion opportunities qualified. At S5, a Renewal Proposal should be on the table. If the Account Plan doesn't reflect these activities, the AE is either not doing them or not documenting them — both are problems. Momentum without strategy is a fragile deal.", resource: { label: "Account Planning Slides — Keeping Account Plans Current", url: DAY7_ACCOUNT } },
  { id: 6, type: "mc", lo: "LO3", text: "In the Momentum Sales Training, what does 'Momentum' refer to and why is it critical to the Amplitude sales process?", options: ["Momentum is the pace of deal progression — it measures how quickly a deal moves through pipeline stages","Momentum is the measurable, forward-moving energy in a deal created by buyer actions, shared milestones, and increasing commitment. It's the observable signal that a deal is real and advancing — not because the AE is pushing, but because the buyer is pulling. Loss of Momentum is one of the earliest signals that a deal is at risk.","Momentum is a scoring metric in SFDC that auto-calculates based on stage, age, and activity count","Momentum is the AE's activity level — more emails, calls, and meetings create more Momentum"], correct: 1, explanation: "Momentum per the training is not AE activity or pipeline velocity — it's observable buyer behavior that signals genuine deal advancement. Buyer actions (introducing new stakeholders, returning calls quickly, completing MAP milestones) create Momentum. AE activity (emails, calls) without buyer response is not Momentum — it's motion. The critical skill is distinguishing between the two. When Momentum stalls, the deal is at risk regardless of what the AE is doing.", resource: { label: "Momentum Sales Training — Defining Momentum", url: DAY7_MOMENTUM } },
  { id: 7, type: "mc", lo: "LO2", text: "A deal has been in S2 for 6 weeks. The Champion responds to emails but hasn't introduced the AE to the Economic Buyer. The AE tells their FLM: 'The deal is progressing — we have good engagement.' Is the AE's assessment correct?", options: ["Yes — consistent email engagement is a strong signal of deal health","No — email responsiveness without stakeholder expansion is activity, not Momentum. A Champion who won't introduce the EB after 6 weeks is either not a real Champion (they lack power or influence) or there's an organizational barrier the AE hasn't uncovered. The right move is to directly address the EB introduction: ask the Champion what's preventing it and offer to help frame the conversation.","Partially — the deal is progressing but slowly. Give it another 2-3 weeks before escalating the EB introduction.","No — 6 weeks in S2 means the deal is dead. Mark it as stalled and move on to higher-priority accounts."], correct: 1, explanation: "This is a classic Momentum misread. Responding to emails feels like engagement but it's not a buying signal — it's politeness. Momentum requires observable buyer commitment: introducing new stakeholders (especially the EB), completing MAP milestones, returning technical evaluation results, allocating internal resources. A Champion who engages but doesn't expand access is either unwilling or unable to champion the deal. The AE needs to surface this directly — not wait and hope.", resource: { label: "Momentum Sales Training — Distinguishing Activity from Momentum", url: DAY7_MOMENTUM } },
  { id: 8, type: "fill", lo: "LO1", text: "In the context of Account Planning, the acronym MAP stands for ________ Action Plan.", correct: ["Mutual","mutual","MUTUAL"], placeholder: "what kind of action plan...", explanation: "MAP = Mutual Action Plan. The word 'Mutual' is the critical part — it means the plan is co-owned by both the AE and the customer. A one-sided action plan (just the AE's tasks) is not a MAP — it's a project plan. The MAP should include steps the customer commits to (introductions, evaluations, procurement timelines) alongside Amplitude's deliverables. Mutual commitment is what makes the MAP a deal-qualifying artifact.", resource: { label: "Account Planning Slides — Mutual Action Plan (MAP)", url: DAY7_ACCOUNT } },
  { id: 9, type: "mc", lo: "LO3", text: "You're reviewing your pipeline in a deal review with your FLM. One of your S3 deals has a Champion, a technical win from the POV, and a verbal commitment from the EB — but no signed MAP and no confirmed decision timeline. Your FLM asks: 'Is this deal real?' What's the honest assessment?", options: ["Yes — a technical win and EB verbal commitment are the two strongest buying signals. The MAP and timeline will follow.","It's directionally real but structurally at risk. Without a signed MAP and a confirmed decision timeline, you have interest but not commitment. The EB's verbal yes is encouraging but hasn't been tested against procurement, legal, budget approval, or competitive alternatives. The MAP is the artifact that converts verbal commitment into documented mutual action. Without it, the deal is one stakeholder change or budget reallocation away from stalling.","No — any deal without a MAP at S3 is not qualified and should be moved back to S2","Yes — but only if the deal has been in S3 for less than 30 days. After 30 days without a MAP, it should be flagged as at risk."], correct: 1, explanation: "This is a nuanced Momentum assessment. The deal has positive signals (Champion, technical win, EB interest) but lacks structural commitment (MAP, timeline). In enterprise sales, verbal commitments without documented next steps are the most common source of deal slippage. The MAP forces both sides to commit to specific actions and timelines — without it, the deal is real in sentiment but not in process. Your FLM is asking because they've seen verbal-yes deals stall many times.", resource: { label: "Momentum Sales Training — Structural vs. Sentimental Deal Health", url: DAY7_MOMENTUM } },
  { id: 10, type: "mc", lo: "LO1", text: "According to the Account Planning framework, how often should a strategic Account Plan be reviewed and updated?", options: ["Quarterly — aligned with business review cycles","Continuously — the Account Plan should be updated after every significant interaction, stakeholder change, or competitive development. It's reviewed formally with the FLM in deal reviews and QBRs, but maintained by the AE as a living document.","Monthly — at the FLM's 1:1 with the AE","Only when deal stage changes — stage transitions trigger Account Plan updates"], correct: 1, explanation: "A strategic Account Plan is a living document. It should be updated after every significant event: new stakeholder identified, competitive intelligence surfaced, business priority shifted, MAP milestone completed or missed. Formal reviews happen in deal reviews and QBRs with the FLM, but the AE is responsible for keeping it current between those touchpoints. An Account Plan that only gets updated at stage transitions misses all the signals between stages — and those are often the most important.", resource: { label: "Account Planning Slides — Account Plan Maintenance & Review Cadence", url: DAY7_ACCOUNT } },
];

const DAY8_DISCOVERY = "https://docs.google.com/document/d/11po0r9LxK_tiooyYb64bdDeqhIhRX_7k-HSlPppf1A4/edit";
const DAY8_CEM = DAY5_CEM;

const v1Day8 = [
  { id: 1, type: "mc", lo: "LO1", text: "The Discovery Question Repository is built to serve multiple GTM roles. Who is it primarily intended for?", options: ["FLMs and enablement managers only — it's a coaching and training resource","AEs, SDRs, SEs, and other GTM practitioners for use before and during customer conversations","SEs only — discovery is a technical function that requires product expertise to execute well","SDRs only — once an AE takes over the opportunity, they should be asking their own questions"], correct: 1, explanation: "The Discovery Question Repository is for AEs, SDRs, SEs, and other GTM practitioners. It's designed as a plug-and-play resource for net new discovery, qualification, POV design, and competitive bake-offs. Enablement and leadership use it for coaching and role-play. The goal: standardize how Amplitude does discovery, tie it to Challenger + MEDDPICC, and accelerate call preparation without starting from scratch every time.", resource: { label: "Discovery Question Repository — Introduction (Who It's For)", url: DAY8_DISCOVERY } },
  { id: 2, type: "mc", lo: "LO2", text: "You're in an S1 Discovery call with a VP of Product at a B2B SaaS company. They say: 'We use a mix of Looker, custom dashboards our engineering team built, and some Google Analytics.' Which discovery question best applies Challenger thinking here?", options: ["'So you have three different tools — which one do you use most?' This clarifies their primary workflow","'How long does it take for a PM on your team to go from a product question to a decision-ready answer — without needing to open a ticket with engineering or data?' This surfaces the cost of fragmentation.","'Have you considered a unified platform? Having three tools creates complexity.' This introduces the solution early.","'Is your engineering team happy managing those custom dashboards?' This checks for internal pain from a technical stakeholder."], correct: 1, explanation: "This is a textbook Challenger discovery move from the Question Repository. A fragmented stack (Looker + custom dashboards + GA) has a real cost — every question that doesn't fit into existing dashboards becomes a ticket. The time-to-answer question surfaces that pain without naming it for them. Let them describe the friction: 'Well, it depends... sometimes a few days.' That's your opening. The other options either accept their frame too quickly or introduce your solution before establishing the problem.", resource: { label: "Discovery Question Repository — S0 Engagement: Context & Current State Questions", url: DAY8_DISCOVERY } },
  { id: 3, type: "mc", lo: "LO2", text: "In the CEM, what must be documented in SFDC before an AE can move from S1 to S2?", options: ["Technical use cases validated by the SE and a demo completed","The 3 Whys (Why Change, Why Now, Why Amplitude), Champion identified, initial MEDDPICC fields populated, and FLM validation of the 3 Whys","A signed NDA and a formal request for proposal from the customer","Budget confirmed and decision timeline documented"], correct: 1, explanation: "Per the CEM S1 Discovery exit criteria: Discovery call completed, 3 Whys documented (Why Change, Why Now, Why Amplitude), Champion and/or EB identified, initial MEDDPICC fields completed in SFDC, and FLM validation of the 3 Whys confirmed. Without FLM validation, you cannot advance to S2. This gate exists to ensure deals are real and winnable before significant resources are committed. Documenting it in SFDC isn't admin — it's proof the discovery was thorough.", resource: { label: "Customer Engagement Model — S1 Discovery Exit Criteria (3 Whys + MEDDPICC)", url: DAY8_CEM } },
  { id: 4, type: "mc", lo: "LO3", text: "A prospect says: 'We're not in a hurry — we're evaluating a few options over the next 6 months.' Using the Discovery Question Repository's 'Why Now' framework, which question best creates urgency without manufacturing false pressure?", options: ["'If you wait 6 months to decide, our pricing will likely increase.' This is honest about timing constraints.","'What's driving the 6-month timeline — is there a budget cycle, a product launch, or a specific problem you're trying to solve by then?' This clarifies if the timeline is real or a deflection.","'OK, let's plan for a follow-up in 5 months then.' This respects their pace without pushing.","'If nothing changes about your analytics setup over the next 6 months, what breaks first?' This surfaces the cost of delay."], correct: 3, explanation: "The Discovery Question Repository's 'Why Now' category asks: 'If nothing changed in your product analytics approach over the next year, what would break first?' This is a Challenger question — it asks the prospect to articulate the cost of inaction without the AE asserting urgency. It's not a pressure move; it's a Teach move. The prospect either identifies a real risk (which is urgency) or they don't (which tells you they're not qualified yet). Option B is also strong but is more clarifying than urgency-creating. Option D is the best fit for creating owned urgency.", resource: { label: "Discovery Question Repository — S0 Engagement: Priority & Timing ('Why Now?')", url: DAY8_DISCOVERY } },
  { id: 5, type: "tf", lo: "LO1", text: "True or False: The 3 Whys framework used in discovery at Amplitude refers to Why Change, Why Amplitude, and Why This Year.", options: ["True","False"], correct: 1, explanation: "The 3 Whys per the CEM are: Why Change (what's broken about the status quo), Why Now (what creates urgency — a product launch, board initiative, competitive pressure, fiscal cycle), and Why Amplitude (why us specifically over other options). All three must be documented in SFDC and validated by your FLM at S1. A deal that can't answer all three should not advance to S2 — missing any one of them is a significant qualification risk.", resource: { label: "Customer Engagement Model — S1 Discovery (3 Whys: Why Change, Why Now, Why Amplitude)", url: DAY8_CEM } },
  { id: 6, type: "mc", lo: "LO3", text: "An SDR hands off an account to an AE with a brief that says: 'VP Product at a FinServ company, showed interest in analytics after downloading the Northstar Playbook.' The AE opens the S1 call and starts with: 'So, tell me about your current setup.' What's wrong with this approach?", options: ["Nothing — open-ended questions are the foundation of good discovery","The AE is wasting the first 5 minutes re-establishing context the SDR already captured. The Discovery Question Repository exists so AEs can seed insights from the first question. A better opening: 'In financial services, we often see PMs struggle to connect product behavior data to revenue outcomes — is that a gap you're experiencing?' This is Challenger from question one.","The AE should have asked for a demo before the discovery call — buyers need to see the product before they'll share information","The SDR's handoff note is insufficient and the AE should reschedule until they have better context"], correct: 1, explanation: "Starting with 'tell me about your current setup' is the opposite of Challenger discovery. The Discovery Question Repository exists specifically to help AEs show up with a point of view — not a blank slate. At S0, the SDR seeded context. At S1, the AE should open with a commercial insight: something about the VP Product's world in Financial Services that challenges their current assumption. The question 'How long does it take a PM to get a decision-ready answer without needing analyst support?' is a much stronger opener than 'tell me about your setup.'", resource: { label: "Discovery Question Repository — S0 Engagement: Context & Current State (Insight-Led Opening)", url: DAY8_DISCOVERY } },
  { id: 7, type: "match", lo: "LO1", text: "Match each MEDDPICC component to what it is designed to validate in discovery.", pairs: [{ term: "Metrics", match: "What quantifiable outcomes does the customer need to achieve — how will they measure success?" },{ term: "Economic Buyer", match: "Who has final budget authority and can say yes or no regardless of what others want?" },{ term: "Champion", match: "Who has power and influence internally AND wants Amplitude to win — will fight for the deal?" },{ term: "Decision Criteria", match: "What are the formal and informal requirements the customer will use to evaluate and select a solution?" }], correct: 0, explanation: "MEDDPICC is the qualification framework that drives deal hygiene at Amplitude. Each component surfaces a different risk in the deal. Metrics without an Economic Buyer = a deal that will die in procurement. A Champion without Metrics = an enthusiastic user who can't build an internal business case. All MEDDPICC fields must be populated by S2 — and the FLM validates them before the deal advances. The Discovery Question Repository has specific questions mapped to each MEDDPICC component.", resource: { label: "Customer Engagement Model — S1 Discovery MEDDPICC Fields", url: DAY8_CEM } },
  { id: 8, type: "fill", lo: "LO1", text: "The website https://builtwith.com is recommended in the Discovery Question Repository as a resource for ________ before prospect conversations.", correct: ["research","account research","prospect research","tech stack research","pre-call research"], placeholder: "what type of preparation...", explanation: "BuiltWith.com is recommended in the Discovery Question Repository as a pre-call research tool. It shows what technologies a prospect is running on their website — analytics tools, tag managers, data tools, CDPs. This intelligence lets you show up to discovery already knowing part of their tech stack, which is a Challenger credibility signal: 'I see you're running [Tool X] — how has that been working for the product team?' It saves time and signals to the prospect that you've done your homework.", resource: { label: "Discovery Question Repository — Resources That Can Help in Discovery (builtwith.com)", url: DAY8_DISCOVERY } },
  { id: 9, type: "mc", lo: "LO3", text: "You're in S2 Qualification with a Head of Data Science at a healthcare tech company. They say: 'Our data team handles all analytics requests — we don't have a self-service problem.' A Challenger AE responds: 'How many ad hoc data requests does your team handle per week?' The Head of Data Science says: 'Oh, easily 30-40.' What's the ideal next Challenger move?", options: ["Pivot to a demo — they've surfaced the pain, now show the solution","Ask: 'What would your team focus on if they weren't fielding those 30-40 requests every week?' This deepens the pain, surfaces the opportunity cost, and lets them articulate the value of self-service in their own words.","Tell them that Amplitude typically reduces ad hoc requests by 60% — quantify the ROI immediately","Loop in the SE for a technical deep-dive — this is a data infrastructure conversation the AE shouldn't be leading"], correct: 1, explanation: "This is the Challenger deepening move — they've just revealed the pain, now make them feel it more fully. 'What would your team focus on if they weren't fielding 30-40 requests a week?' forces the Head of Data Science to articulate their own strategic opportunity cost. The answer to that question is your business case. You're not selling Amplitude — you're helping them realize what they're losing. Moving to demo now cuts the discovery short before the pain is fully owned. Quantifying ROI prematurely tells rather than asks — and claims you haven't yet earned.", resource: { label: "Discovery Question Repository — S1 Discovery: Pain & Friction Surfacing", url: DAY8_DISCOVERY } },
  { id: 10, type: "mc", lo: "LO2", text: "After a successful S1 Discovery, you need to prepare a POV (Proof of Value) plan for S3. According to the CEM and the Discovery Question Repository, what must you have validated in discovery BEFORE designing the POV?", options: ["The prospect's budget and procurement timeline — you can't design a POV without knowing the financial parameters","The 3 Whys, at least 2 validated use cases tied to specific personas, and initial MEDDPICC fields. The POV must address the customer's articulated pain — not Amplitude's standard demo script. Use cases should map to the personas you've engaged and the business outcomes they described.","The technical architecture of the prospect's data stack — the SE needs this to build the right POV environment","At least 3 customer references in the same industry — social proof is the foundation of a strong POV"], correct: 1, explanation: "A POV that doesn't connect to validated discovery is a feature demo in disguise. Before designing the POV, you need: the 3 Whys documented (Why Change, Why Now, Why Amplitude), at least 2 use cases tied to specific personas (not generic Amplitude use cases), and initial MEDDPICC fields populated. The POV should address the exact pain the prospect described — not a pre-built demo. This is why discovery depth matters: shallow discovery produces generic POVs that don't convert.", resource: { label: "Discovery Question Repository — POV Design Principles (Discovery-Validated Use Cases)", url: DAY8_DISCOVERY } },
];

const DAY9_PRICING = "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit";

const v1Day9 = [
  { id: 1, type: "mc", lo: "LO1", text: "What are the four platform tiers in Amplitude's 2026 PPL, in order from entry-level to highest?", options: ["Basic, Professional, Business, Enterprise","Starter, Plus, Growth, Enterprise","Free, Growth, Enterprise, Custom","Starter, Growth, Enterprise, Signature"], correct: 1, explanation: "The 2026 PPL has four platform tiers: Starter (free, up to 10K MTU), Plus (up to 50M Events or 500K MTU), Growth (custom events/MTU), and Enterprise (custom events/MTU with the most advanced capabilities). Each tier includes increasing access to platform features, with add-ons available for Growth and Enterprise. Knowing the tiers is foundational — every pricing conversation starts here.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — New Packaging & Pricing (Platform Tiers)", url: DAY9_PRICING } },
  { id: 2, type: "mc", lo: "LO2", text: "A prospect asks: 'How is Amplitude priced? Is it per user?' What's the correct explanation of the 2026 pricing model?", options: ["Per user per month — each named user who logs in is billed","Per event — you pay for the total volume of events tracked across all users and products. The unit rate varies by tier and volume. There are no per-seat charges for analytics users.","Per API call — each query against the analytics engine is metered and billed","Flat annual fee with overages — you pay a fixed price for a set capacity, then overages are billed quarterly"], correct: 1, explanation: "Amplitude's 2026 PPL is priced per event — not per user, per seat, or per API call. The unit rate varies by tier (Starter is free up to 10K MTU, Plus/Growth/Enterprise have volume-based event pricing). This is a critical positioning point: no per-seat charges means analytics access can be democratized across the organization without cost anxiety. Every PM, analyst, marketer, and executive can have access without someone tracking licenses.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Pricing Model Overview", url: DAY9_PRICING } },
  { id: 3, type: "mc", lo: "LO1", text: "What is the maximum event volume included in the Plus tier, and what happens if a customer exceeds it?", options: ["10M events — overages are billed at 2x the contracted rate","50M Events or 500K MTU — customers who exceed these thresholds need to move to Growth or Enterprise tier for custom volume pricing","100M events — no overage charges, but analytics performance degrades above this threshold","Unlimited events — Plus tier has no volume cap, only feature limitations compared to Growth"], correct: 1, explanation: "The Plus tier includes up to 50M Events or 500K MTU. Customers who exceed these thresholds need to upgrade to Growth or Enterprise, which offer custom volume pricing. This threshold is important in deal-shaping: if a prospect's event volume is close to 50M, the conversation should proactively address growth trajectory and the path to Growth tier — don't let them hit the wall and create a reactive upgrade conversation.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Plus Tier (Volume Thresholds)", url: DAY9_PRICING } },
  { id: 4, type: "mc", lo: "LO2", text: "A prospect is on the Growth tier and wants to add Session Replay. How is the Session Replay add-on priced?", options: ["Flat fee per month — Session Replay has a fixed price regardless of platform tier","15% of the SW Pillar net total — Session Replay is priced as a percentage of the customer's core platform spend","Per session recorded — each replayed session is billed individually at a metered rate","Free with Growth tier — Session Replay is included in Growth and above at no additional charge"], correct: 1, explanation: "Session Replay is priced at 15% of the SW Pillar net total. This percentage-of-platform pricing model means the add-on cost scales with the customer's overall Amplitude investment. At 15%, Session Replay is positioned as an accessible entry point that deepens platform stickiness. Knowing the POT percentage for each add-on helps you scope deals quickly without needing Deal Desk for every estimate.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Add-On Pricing (POT Percentages)", url: DAY9_PRICING } },
  { id: 5, type: "match", lo: "LO1", text: "Match each add-on product to its POT percentage of the SW Pillar net total.", pairs: [{ term: "Session Replay", match: "15% of SW Pillar net total" },{ term: "Feature Experimentation", match: "50% of SW Pillar net total" },{ term: "Web Experimentation", match: "30% of SW Pillar net total" },{ term: "Guides & Surveys", match: "30% of SW Pillar net total" }], correct: 0, explanation: "POT percentages are the key pricing facts for add-on conversations. Feature Experimentation at 50% reflects its strategic value and depth. Session Replay and AI Feedback at 15% are positioned as accessible entry points that deepen platform stickiness. Guides & Surveys, Web Experimentation, and Activation at 30% reflect their high usage footprint. Knowing these rates helps you scope deals quickly and position add-ons confidently without needing to open a Deal Desk case for every estimate.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Add-On Pricing (POT Percentages)", url: DAY9_PRICING } },
  { id: 6, type: "tf", lo: "LO1", text: "True or False: The 2026 PPL has a platform fee (minimum spend floor) in addition to volume-based pricing.", options: ["True","False"], correct: 1, explanation: "One of the key simplifications in 2026 PPL is the removal of the platform fee. Previous plans had minimum fees that made low-volume deals appear expensive relative to what customers were getting. The new model: one unit rate per tier, no floor, no platform minimum. This makes pricing more transparent and easier to explain to buyers — and reduces churn risk from customers who feel they're paying for capacity they're not using.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — No Platform Fee or Minimum Block Pricing", url: DAY9_PRICING } },
  { id: 7, type: "mc", lo: "LO2", text: "A prospect asks about a 3-year deal. Your standard term is 3 years — what is the pricing implication for shorter terms?", options: ["Shorter terms get discounts — 1-year deals are cheaper than 3-year deals","All term lengths are priced the same — Amplitude doesn't discount based on commitment length","Standard term is 3 years. For each year reduced, price is uplifted by 5-10%. A 1-year deal costs 10-20% more than the same 3-year commitment.","Shorter terms require Deal Desk approval but carry no pricing premium"], correct: 2, explanation: "Per the 2026 PPL: standard term is 3 years. For each year reduced from the standard, uplift price by 5-10%. This creates a meaningful incentive for multi-year commitments — a 1-year deal is priced 10-20% higher than the equivalent 3-year deal. This is part of 'weaponizing pricing' to create commercially attractive structures that benefit both Amplitude and the customer. Use this to position multi-year deals: 'If we can structure this as a 3-year, here's what that does for your unit price.'", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Weaponizing Pricing: Standard Term & Uplift", url: DAY9_PRICING } },
  { id: 8, type: "fill", lo: "LO1", text: "The entry-level free tier in Amplitude's 2026 PPL is called ________ and includes up to 10K Monthly Tracked Users.", correct: ["Starter","starter","STARTER","the Starter plan","Starter plan"], placeholder: "tier name...", explanation: "The Starter tier is Amplitude's free entry point — up to 10K MTU with core analytics capabilities. It's designed as a land-and-expand lever: teams can start using Amplitude at no cost, build internal adoption, and then convert to Plus or Growth as their usage and needs grow. Knowing the Starter tier's positioning helps when prospecting into accounts that might be on Starter already — they're not cold prospects, they're warm conversion candidates.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Starter Tier Overview", url: DAY9_PRICING } },
  { id: 9, type: "mc", lo: "LO3", text: "You're preparing a renewal proposal for a Growth-tier customer. They currently have the core platform and Session Replay. They want to add Feature Experimentation. How do you estimate the Feature Experimentation price for the proposal?", options: ["Look up the Feature Experimentation list price in the price book — it's a fixed annual fee","Calculate 50% of the customer's SW Pillar net total (their current core platform spend). That's the Feature Experimentation price. Add it to the renewal proposal alongside the existing platform and Session Replay costs.","Ask Deal Desk — add-on pricing requires custom quotes for every deal","Estimate based on the customer's event volume — Feature Experimentation is priced per experiment run"], correct: 1, explanation: "Feature Experimentation is 50% of the SW Pillar net total. If the customer's core platform spend is $100K, Feature Experimentation is approximately $50K. This POT pricing model is designed so AEs can quickly estimate add-on costs without waiting for Deal Desk on every proposal. For formal proposals, Deal Desk validates — but knowing the POT percentages lets you have confident pricing conversations with customers before the formal process begins.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Add-On Pricing (Feature Experimentation at 50%)", url: DAY9_PRICING } },
  { id: 10, type: "mc", lo: "LO3", text: "A customer on Enterprise tier is evaluating whether to add Guides & Surveys or Web Experimentation. Both are priced at 30% POT. They ask: 'Which one should we start with?' How do you apply the 2026 PPL positioning to guide this conversation?", options: ["Recommend both — since they're the same price, the customer gets more value by adopting both simultaneously","Ask which use case is more urgent: if they need to improve user onboarding and in-app engagement, Guides & Surveys addresses that directly. If they need to optimize web conversion rates and landing pages, Web Experimentation is the right starting point. The pricing is the same, so the decision is use-case-driven, not cost-driven.","Recommend Guides & Surveys — it has broader applicability and higher adoption rates across Amplitude's customer base","Recommend Web Experimentation — it has a faster time-to-value because it doesn't require product instrumentation"], correct: 1, explanation: "When two products are priced the same, the decision should be driven by use case, not cost. Guides & Surveys = in-app engagement, onboarding, feedback collection. Web Experimentation = website conversion optimization, A/B testing landing pages. Ask the customer: what's the biggest gap in your current stack? Where would you see value fastest? This is consultative selling — matching the product to the pain, not pushing the product with the highest attach rate.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Positioning Add-Ons by Use Case", url: DAY9_PRICING } },
];

const V1_QUESTIONS: Record<string, object[]> = {
  day1: v1Day1,
  day2: v1Day2,
  day3: v1Day3,
  day4: v1Day4,
  day5: v1Day5,
  day6: v1Day6,
  day7: v1Day7,
  day8: v1Day8,
  day9: v1Day9,
};

export default api({
  name: "CampBackfillSnapshots",
  description: "Backfills v1 question snapshots for all existing attempts without snapshots",
  integrations: {
    db: postgres(APPS_DB),
  },
  input: z.object({
    userEmail: z.string(),
  }),
  output: z.object({
    backfilled: z.number(),
    skipped: z.number(),
    details: z.array(z.object({
      attemptId: z.number(),
      quizId: z.string(),
      status: z.string(),
    })),
  }),
  async run(ctx, { userEmail }) {
    // Admin check
    if (!ADMIN_EMAILS.includes(userEmail.toLowerCase())) {
      throw new Error("Only admins can run backfill operations");
    }

    // Find all attempts without snapshots
    const attempts = await ctx.integrations.db.query(
      `SELECT a.id, a.quiz_id
       FROM camp_quiz_attempts a
       LEFT JOIN camp_quiz_snapshots s ON s.attempt_id = a.id
       WHERE s.id IS NULL
       ORDER BY a.id`,
      z.object({ id: z.coerce.number(), quiz_id: z.string() }),
      [],
      { label: "Find attempts without snapshots" }
    );

    let backfilled = 0;
    let skipped = 0;
    const details: { attemptId: number; quizId: string; status: string }[] = [];

    for (const attempt of attempts) {
      const questions = V1_QUESTIONS[attempt.quiz_id];
      if (!questions) {
        skipped++;
        details.push({ attemptId: attempt.id, quizId: attempt.quiz_id, status: "skipped_no_v1_data" });
        continue;
      }

      await ctx.integrations.db.execute(
        `INSERT INTO camp_quiz_snapshots (attempt_id, quiz_id, questions_json)
         VALUES ($1, $2, $3)
         ON CONFLICT (attempt_id) DO NOTHING`,
        [attempt.id, attempt.quiz_id, JSON.stringify(questions)],
        { label: `Backfill snapshot for attempt ${attempt.id} (${attempt.quiz_id})` }
      );

      backfilled++;
      details.push({ attemptId: attempt.id, quizId: attempt.quiz_id, status: "backfilled" });
    }

    return { backfilled, skipped, details };
  },
});
